import React, { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import styles from "./button-lang.module.css";

interface ButtonLangProps {
  lang: string;
  isActive: boolean;
}

const ButtonLang: React.FC<ButtonLangProps> = ({ lang, isActive }) => {
  const { i18n } = useTranslation();
  const [activeLanguage, setActiveLanguage] = useState<string>(
    localStorage.getItem("selectedLanguage") || lang
  );

  useEffect(() => {
    // Update the language when the component mounts
    i18n.changeLanguage(activeLanguage);
  }, [i18n, activeLanguage]);

  useEffect(() => {
    // Update the activeLanguage state when the isActive prop changes
    if (isActive) {
      setActiveLanguage(lang);
    }

  }, [isActive, lang]);

  const changeLanguage = (language: string) => {
    i18n.changeLanguage(language);
    setActiveLanguage(language);
    localStorage.setItem("selectedLanguage", language); // Save selected language to localStorage
  };

  return (
      <button
        className={`${styles.btn_lang} ${isActive ? styles.btn_active : ""}`} 
        onClick={() => changeLanguage(lang)}
      >
        {lang.toUpperCase()}
      </button>
  );
};

export default ButtonLang;
